1	// claim-office.ts
2	
3	export type Item = {
4	  type: string;
5	  material?: string;
6	  enchantment?: number;
7	  cursed?: boolean;
8	};
9	
10	export type QuoteInput = {
11	  items: Item[];
12	  customerYears: number;
13	  previousContracts: number;
14	};
15	
16	const PROCESSING_FEE = 5;
17	const COMPONENT_BLOCK_SIZE = 3;
18	const COMPONENT_BLOCK_PREMIUM = 60;
19	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
20	const CURSE_SURCHARGE_RATE = 0.5;
21	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
22	const HIGH_ENCHANTMENT_THRESHOLD = 5;
23	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
24	const LOYALTY_DISCOUNT_RATE = 0.2;
25	const LOYALTY_YEARS_THRESHOLD = 2;
26	const FOLLOWUP_DISCOUNT_RATE = 0.15;
27	const DEDUCTIBLE = 100;
28	const HIGH_ENCHANTMENT_DAMAGE_THRESHOLD = 8;
29	const HIGH_ENCHANTMENT_DAMAGE_REIMBURSEMENT_RATE = 0.5;
30	
31	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
32	  sword: 100,
33	  amulet: 60,
34	  staff: 80,
35	  potion: 40,
36	  rune: 25,
37	  moonstone: 25,
38	};
39	
40	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
41	  sword: 1000,
42	  amulet: 600,
43	  staff: 800,
44	  potion: 400,
45	  rune: 250,
46	  moonstone: 250,
47	};
48	
49	function groupByType(items: Item[]): Map<string, Item[]> {
50	  const groups = new Map<string, Item[]>();
51	  for (const item of items) {
52	    const group = groups.get(item.type) ?? [];
53	    group.push(item);
54	    groups.set(item.type, group);
55	  }
56	  return groups;
57	}
58	
59	function premiumForGroup(type: string, group: Item[]): number {
60	  if (COMPONENT_TYPES.has(type) && group.length === COMPONENT_BLOCK_SIZE) {
61	    return COMPONENT_BLOCK_PREMIUM;
62	  }
63	  return group.length * BASE_PREMIUM_BY_TYPE[type];
64	}
65	
66	function isEnchantmentAtLeast(item: Item, threshold: number): boolean {
67	  return item.enchantment !== undefined && item.enchantment >= threshold;
68	}
69	
70	function modifierRateForItem(item: Item): number {
71	  let rate = 0;
72	  if (item.cursed) {
73	    rate += CURSE_SURCHARGE_RATE;
74	  }
75	  if (isEnchantmentAtLeast(item, HIGH_ENCHANTMENT_THRESHOLD)) {
76	    rate += HIGH_ENCHANTMENT_SURCHARGE_RATE;
77	  }
78	  return rate;
79	}
80	
81	function premiumForModifiedItem(item: Item): number {
82	  const base = BASE_PREMIUM_BY_TYPE[item.type];
83	  return base + base * modifierRateForItem(item);
84	}
85	
86	function hasCursedItem(items: Item[]): boolean {
87	  return items.some((item) => item.cursed);
88	}
89	
90	function hasHighEnchantmentItem(items: Item[]): boolean {
91	  return items.some((item) => isEnchantmentAtLeast(item, HIGH_ENCHANTMENT_THRESHOLD));
92	}
93	
94	function hasItemModifier(items: Item[]): boolean {
95	  return hasCursedItem(items) || hasHighEnchantmentItem(items);
96	}
97	
98	function sumByType(items: Item[], valueByType: Record<string, number>): number {
99	  return items.reduce((sum, item) => sum + valueByType[item.type], 0);
100	}
101	
102	function baseTotalForItems(items: Item[]): number {
103	  return sumByType(items, BASE_PREMIUM_BY_TYPE);
104	}
105	
106	function premiumForItems(items: Item[]): number {
107	  if (hasItemModifier(items)) {
108	    return items.reduce((sum, item) => sum + premiumForModifiedItem(item), 0);
109	  }
110	  return Array.from(groupByType(items)).reduce(
111	    (sum, [type, group]) => sum + premiumForGroup(type, group),
112	    0,
113	  );
114	}
115	
116	function qualifiesForFirstInsuranceSurcharge(input: QuoteInput): boolean {
117	  return input.items.length === 1 && hasItemModifier(input.items);
118	}
119	
120	function qualifiesForLoyaltyDiscount(input: QuoteInput): boolean {
121	  return input.customerYears >= LOYALTY_YEARS_THRESHOLD;
122	}
123	
124	function qualifiesForFollowupDiscount(input: QuoteInput): boolean {
125	  return input.previousContracts >= 1;
126	}
127	
128	export type Damage = {
129	  itemType: string;
130	  amount: number;
131	};
132	
133	export type ClaimInput = {
134	  items: Item[];
135	  remainingCap: number;
136	  damages: Damage[];
137	};
138	
139	export type ClaimResult = {
140	  payout: number;
141	  remainingCap: number;
142	};
143	
144	function payoutForDamage(damage: Damage, items: Item[]): number {
145	  const item = items.find((i) => i.type === damage.itemType);
146	  const isHighEnchantmentDamage =
147	    item !== undefined && isEnchantmentAtLeast(item, HIGH_ENCHANTMENT_DAMAGE_THRESHOLD);
148	  const reimbursement = isHighEnchantmentDamage
149	    ? damage.amount * HIGH_ENCHANTMENT_DAMAGE_REIMBURSEMENT_RATE
150	    : damage.amount;
151	  return reimbursement - DEDUCTIBLE;
152	}
153	
154	export function claim(input: ClaimInput): ClaimResult {
155	  const { items, remainingCap, damages } = input;
156	  const uncappedPayout = damages.reduce(
157	    (sum, damage) => sum + payoutForDamage(damage, items),
158	    0,
159	  );
160	  const payout = Math.min(Math.floor(uncappedPayout), remainingCap);
161	  return { payout, remainingCap: remainingCap - payout };
162	}
163	
164	export function insuranceSum(items: Item[]): number {
165	  return sumByType(items, INSURANCE_VALUE_BY_TYPE);
166	}
167	
168	export function quote(input: QuoteInput): number {
169	  let premium = premiumForItems(input.items);
170	  const baseTotal = baseTotalForItems(input.items);
171	  if (qualifiesForFirstInsuranceSurcharge(input)) {
172	    premium += baseTotal * FIRST_INSURANCE_SURCHARGE_RATE;
173	  }
174	  if (qualifiesForLoyaltyDiscount(input)) {
175	    premium -= baseTotal * LOYALTY_DISCOUNT_RATE;
176	  }
177	  if (qualifiesForFollowupDiscount(input)) {
178	    premium -= baseTotal * FOLLOWUP_DISCOUNT_RATE;
179	  }
180	  return Math.ceil(premium + PROCESSING_FEE);
181	}
