13	type QuoteStep = { op: "quote"; items: Item[] };
14	type ClaimStep = {
15	  op: "claim";
16	  policy: number;
17	  incident: { cause: string; damages: { itemType: string; amount: number }[] };
18	};
19	type Step = QuoteStep | ClaimStep;
20	
21	type Scenario = {
22	  customer: { yearsWithMHPCO: number };
23	  steps: Step[];
24	};
