26	async function readStdin(): Promise<string> {
27	  const chunks: Buffer[] = [];
28	  for await (const chunk of process.stdin) {
29	    chunks.push(chunk as Buffer);
30	  }
31	  return Buffer.concat(chunks).toString("utf8");
32	}
