34	async function main() {
35	  const raw = await readStdin();
36	  const scenario: Scenario = JSON.parse(raw);
37	
38	  const results: Array<
39	    { premium: number } | { payout: number; remainingCap: number }
40	  > = [];
41	
42	  const policyCaps: number[] = [];
43	  const policyItems: Item[][] = [];
44	  let previousContracts = 0;
45	
46	  for (const step of scenario.steps) {
47	    if (step.op === "quote") {
48	      for (const item of step.items) {
49	        if (!KNOWN_ITEM_TYPES.has(item.type)) {
50	          console.error(`Unknown item type: ${item.type}`);
51	          process.exit(1);
52	        }
53	      }
54	      const premium = quote({
55	        items: step.items,
56	        customerYears: scenario.customer.yearsWithMHPCO,
57	        previousContracts,
58	      });
59	      results.push({ premium });
60	      policyItems.push(step.items);
61	      policyCaps.push(insuranceSum(step.items) * 2);
62	      previousContracts += 1;
63	    } else if (step.op === "claim") {
64	      const idx = step.policy;
65	      const items = policyItems[idx];
66	      const remainingCap = policyCaps[idx];
67	      const result = claim({
68	        items,
69	        remainingCap,
70	        damages: step.incident.damages,
71	      });
72	      policyCaps[idx] = result.remainingCap;
73	      results.push(result);
74	    }
75	  }
76	
77	  console.log(JSON.stringify({ results }));
78	}
79	
80	main().catch((err) => {
81	  console.error(err instanceof Error ? err.message : String(err));
82	  process.exit(1);
83	});
